INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('locality-d592fc58-moex-00098', 'locality-d592fc58', 'locality-d592fc58-moex-112-9b7ab1bb', 'sub-locality-d592fc58-05', NULL, 'single_choice', '甲、乙、丙為三兄弟，甲與丁結婚，丙與戊結婚，乙未婚但認領庚。己為戊之妹。下列關於親屬 關係之敘述，何者錯誤？', '["丁庚間無親屬關係", "庚戊間為姻親關係", "己庚間無親屬關係", "丁戊間為姻親關係"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:25+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "320", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
  ('locality-d592fc58-moex-00099', 'locality-d592fc58', 'locality-d592fc58-moex-112-9b7ab1bb', 'sub-locality-d592fc58-05', NULL, 'single_choice', '甲男乙女為夫妻，因乙女與丁男通姦，甲、乙乃於民國（下同）105年3月1日辦妥協議離婚登 記。105年4月1日乙女與丙男辦理結婚登記。同年12月1日乙女生下一子戊。事實上，戊之生 父為丁。下列敘述何者錯誤？', '["戊可推定為甲男之子", "戊可推定為丙男之子", "丁得認領戊", "戊可同時推定為甲男、丙男之子"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:25+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "320", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
  ('locality-d592fc58-moex-00100', 'locality-d592fc58', 'locality-d592fc58-moex-112-9b7ab1bb', 'sub-locality-d592fc58-05', NULL, 'single_choice', '甲男乙女為夫妻，有一子丙。丙已成年，未婚無子。甲之母丁尚生存。若甲、丙同時死亡，下列 關於丙之遺產繼承之敘述，何者正確？', '["乙繼承甲遺產三分之二、丁繼承甲遺產三分之一；乙繼承丙遺產全部", "甲、乙共同繼承丙之遺產，然後再由乙單獨繼承甲之全部遺產", "乙繼承甲遺產二分之一、丁繼承甲遺產二分之一；乙繼承丙遺產三分之二、丁繼承丙遺產三分 之一", "乙繼承甲遺產二分之一、丁繼承甲遺產二分之一；乙繼承丙遺產全部"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:25+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "320", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
  ('locality-d592fc58-moex-00101', 'locality-d592fc58', 'locality-d592fc58-moex-112-9b7ab1bb', 'sub-locality-d592fc58-05', NULL, 'single_choice', '密封遺囑為要式行為，若不具備法定方式，其效力如何？', '["遺囑效力未定，得隨時拒絕承認", "須經遺囑人的承認後，並經公證，始發生效力", "經法院認可後，得為有效", "密封遺囑雖然無效，然若具備自書遺囑之方式者，有自書遺囑之效力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:25+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "320", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
  ('locality-d592fc58-moex-00102', 'locality-d592fc58', 'locality-d592fc58-moex-112-9b7ab1bb', 'sub-locality-d592fc58-05', NULL, 'single_choice', '甲為乙之父。關於甲乙之扶養關係，下列敘述何者正確？', '["乙成年後，甲因負擔對乙之扶養義務而不能維持自己生活者，得減輕其義務", "乙成年後，對甲不予扶養，即當然喪失對甲之繼承權", "乙未成年時，不服甲之管教，對甲故意為重大侮辱，甲不得請求減輕對乙之扶養義務", "乙未成年時，甲未盡扶養義務，因扶養請求權各自獨立，甲當然得請求成年後之乙為扶養，乙 不得拒絕"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:25+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "320", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
  ('locality-d592fc58-moex-00103', 'locality-d592fc58', 'locality-d592fc58-moex-112-9b7ab1bb', 'sub-locality-d592fc58-05', NULL, 'single_choice', '甲中年喪偶，僅有一子A。今甲死亡，留有未清償之債務數筆，以及土地、存款等財產。A有依 法開具遺產清冊，陳報法院。有關甲遺產之繼承，下列敘述何者錯誤？', '["A依法陳報法院時，法院應依公示催告程序公告，命甲之債權人於一定期限內報明其債權", "A在法院公示催告甲之債權人報明債權所定一定期限內，得對於甲之受遺贈人交付遺贈", "甲之債權人，如不於法院公示催告所定之一定期限內報明其債權，而又為A所不知者，僅得就 賸餘遺產，行使其權利", "在法院公示催告甲之債權人報明債權所定一定期限屆滿後，A 對於在該一定期限內報明之債 權及A所已知之債權，均應按其數額，比例計算，以遺產分別償還。但不得害及有優先權人 之利益"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:25+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "320", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
