  ('locality-d592fc58-moex-00107', 'locality-d592fc58', 'locality-d592fc58-moex-112-d3ff7f6b', 'sub-locality-d592fc58-02', NULL, 'single_choice', '假設A國只生產汽車與電腦兩種產品，在不能與其他國家進行貿易的情況下，如果100萬部汽車 與2,000萬部電腦正好落在A國的生產可能線上，則A國不可能生產下列那一個商品組合？', '["80萬部汽車與1,600萬部電腦", "80萬部汽車與2,000萬部電腦", "100萬部汽車與1,600萬部電腦", "120萬部汽車與2,000萬部電腦"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:25+00:00", "source_pdf_sha1": "876ca4244349", "answer_pdf_sha1": "494374bd7a58", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "320", "s": "1502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL)
